import{_ as t,a as o,b as a,c as i}from"./chunks/settings-about.vgbS8WoP.js";import{_ as n}from"./chunks/settings-add-model.Cxj4wiLe.js";import{_ as r,o as s,c as l,ag as d}from"./chunks/framework.BqfgOMAh.js";const x=JSON.parse('{"title":"Settings","description":"","frontmatter":{},"headers":[],"relativePath":"en/guide/settings.md","filePath":"en/guide/settings.md"}'),u={name:"en/guide/settings.md"};function c(h,e,p,g,m,f){return s(),l("div",null,[...e[0]||(e[0]=[d('<h1 id="settings" tabindex="-1">Settings <a class="header-anchor" href="#settings" aria-label="Permalink to &quot;Settings&quot;">​</a></h1><p>NexusFlow&#39;s Settings page uses an iOS-style navigation design to manage AI models, the global LLM proxy, agent behavior, hotkeys, appearance, and related configuration. Click the gear icon at the top of the sidebar to access Settings.</p><h2 id="ai-models" tabindex="-1">AI Models <a class="header-anchor" href="#ai-models" aria-label="Permalink to &quot;AI Models&quot;">​</a></h2><p>Managing AI models is the first step to using NexusFlow. Here you can add, validate, and manage multiple AI models.</p><h3 id="model-list" tabindex="-1">Model List <a class="header-anchor" href="#model-list" aria-label="Permalink to &quot;Model List&quot;">​</a></h3><p><img src="'+t+'" alt="AI Model settings page"></p><p>Added models are displayed as cards, each showing:</p><ul><li><strong>Model name</strong> and <strong>Provider badge</strong></li><li><strong>Validation status</strong>: Whether the connection test has passed</li><li><strong>Default indicator</strong>: Marks the currently active default model</li></ul><p>Click a card to expand and view details including model identifier, API Key (masked for directly entered keys; variable name for environment references), Base URL, Temperature, and Max Tokens.</p><h3 id="model-actions" tabindex="-1">Model Actions <a class="header-anchor" href="#model-actions" aria-label="Permalink to &quot;Model Actions&quot;">​</a></h3><p>For each added model, you can:</p><ul><li><strong>Validate</strong>: Test whether the API Key and connection are working</li><li><strong>Set as Default</strong>: Use this model as the default for AI conversations</li><li><strong>Delete</strong>: Remove a model configuration you no longer need</li></ul><h3 id="adding-a-new-model" tabindex="-1">Adding a New Model <a class="header-anchor" href="#adding-a-new-model" aria-label="Permalink to &quot;Adding a New Model&quot;">​</a></h3><p>Click the &quot;Add Model&quot; button to open the configuration form:</p><p><img src="'+n+'" alt="Add Model form"></p><p><strong>1. Select Provider</strong></p><p>The following AI service providers are supported:</p><table tabindex="0"><thead><tr><th>Provider</th><th>Description</th></tr></thead><tbody><tr><td>OpenAI</td><td>GPT series models</td></tr><tr><td>Anthropic</td><td>Claude series models</td></tr><tr><td>Google Gemini</td><td>Gemini series models</td></tr><tr><td>DeepSeek</td><td>DeepSeek series models</td></tr><tr><td>Zhipu GLM</td><td>Zhipu GLM series models</td></tr><tr><td>MiniMax</td><td>MiniMax series models</td></tr><tr><td>Qwen</td><td>Alibaba Qwen series models</td></tr><tr><td>Kimi</td><td>Moonshot Kimi series models</td></tr><tr><td>Custom</td><td>Custom API endpoint</td></tr></tbody></table><p><strong>2. Basic Information</strong></p><ul><li><strong>Model Name</strong> (required): A custom name for easy identification</li><li><strong>API Key</strong> (required): Your service provider&#39;s API key; you can also enter an environment variable reference such as <code>${OPENAI_API_KEY}</code>, with the real key resolved by the backend at runtime and only the variable reference stored in app configuration</li><li><strong>Model Identifier</strong> (required): The specific model ID, e.g., <code>gpt-5.4</code>, <code>claude-opus-4-6</code></li></ul><p><strong>3. Optional Settings</strong></p><ul><li><strong>Temperature</strong>: Controls response randomness. Slider range 0 – 2; lower values produce more deterministic responses</li><li><strong>Max Tokens</strong>: Maximum number of tokens per AI response</li></ul><div class="tip custom-block"><p class="custom-block-title">Anthropic Protocol Note</p><p>When using the Anthropic Messages API protocol, Max Tokens is <strong>required</strong>.</p></div><p><strong>4. Custom Provider Configuration</strong></p><p>When selecting Custom, you need to provide additional settings:</p><ul><li><strong>API URL</strong>: Your custom API endpoint URL</li><li><strong>Communication Protocol</strong>: Select the protocol compatible with your target API <ul><li>OpenAI Compatible</li><li>OpenAI Responses API</li><li>Anthropic Messages API</li><li>Google Gemini API</li></ul></li></ul><h2 id="llm-proxy" tabindex="-1">LLM Proxy <a class="header-anchor" href="#llm-proxy" aria-label="Permalink to &quot;LLM Proxy&quot;">​</a></h2><p>The LLM proxy is an independent global setting under Settings → LLM Proxy. It only affects requests from the NexusFlow desktop app to LLM services, and does not route internal UE Plugin, Rust Bridge, MCP Server, or window communication through the proxy.</p><p>Available fields:</p><ul><li><strong>Enable Proxy</strong>: Turn the global LLM proxy on or off.</li><li><strong>Protocol</strong>: HTTP, HTTPS, SOCKS4, or SOCKS5.</li><li><strong>Host / Port</strong>: Proxy server address, for example <code>127.0.0.1:10808</code>.</li><li><strong>Username / Password</strong>: Optional proxy authentication. Passwords are stored with NexusFlow&#39;s encrypted secret storage and are not written to the regular settings file.</li><li><strong>Test Proxy Connectivity</strong>: Only checks whether the proxy host and port are reachable. It does not verify access to a specific LLM service.</li></ul><div class="warning custom-block"><p class="custom-block-title">Proxy rule note</p><p>If your local proxy application has rules such as &quot;bypass mainland China IPs&quot;, NexusFlow may still send the LLM request to the local proxy, but the proxy application can choose a direct connection based on the target server. If you need forced proxying, disable the bypass rule or add a force-proxy rule for your LLM service.</p></div><h2 id="agent-configuration" tabindex="-1">Agent Configuration <a class="header-anchor" href="#agent-configuration" aria-label="Permalink to &quot;Agent Configuration&quot;">​</a></h2><p>Configure the behavior of the AI assistant.</p><h3 id="max-iterations" tabindex="-1">Max Iterations <a class="header-anchor" href="#max-iterations" aria-label="Permalink to &quot;Max Iterations&quot;">​</a></h3><p>Set the maximum number of tool invocation rounds the AI can perform in a single conversation. Range: 1 – 1000.</p><ul><li>The default value works well for most scenarios</li><li>Complex Blueprint operations may require more iterations</li><li>Setting it too low may prevent the AI from completing complex tasks</li></ul><h3 id="response-language" tabindex="-1">Response Language <a class="header-anchor" href="#response-language" aria-label="Permalink to &quot;Response Language&quot;">​</a></h3><p>Control the language the AI uses in its replies, independent of the interface language:</p><ul><li><strong>Follow interface language</strong>: Uses the same language as the UI</li><li><strong>简体中文</strong> (Simplified Chinese)</li><li><strong>繁體中文</strong> (Traditional Chinese)</li><li><strong>English</strong></li></ul><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>You can set the interface to English while having the AI reply in Chinese, or vice versa.</p></div><h2 id="hotkeys" tabindex="-1">Hotkeys <a class="header-anchor" href="#hotkeys" aria-label="Permalink to &quot;Hotkeys&quot;">​</a></h2><p><img src="'+o+'" alt="Hotkeys settings"></p><p>Customize NexusFlow&#39;s keyboard shortcuts.</p><h3 id="global-hotkeys" tabindex="-1">Global Hotkeys <a class="header-anchor" href="#global-hotkeys" aria-label="Permalink to &quot;Global Hotkeys&quot;">​</a></h3><p>Shortcuts that work from any application:</p><ul><li><strong>Toggle Sidebar</strong>: A custom key combination to quickly show or hide the NexusFlow sidebar</li></ul><p>Click the hotkey input field, then press your desired key combination to record it.</p><h3 id="application-hotkeys" tabindex="-1">Application Hotkeys <a class="header-anchor" href="#application-hotkeys" aria-label="Permalink to &quot;Application Hotkeys&quot;">​</a></h3><p>Shortcuts that only work within the NexusFlow window:</p><ul><li><strong>Send Message</strong>: Choose <strong>Enter</strong> or <strong>Ctrl+Enter</strong> as the send shortcut <ul><li><strong>Enter</strong>: Press Enter to send; Shift+Enter for a new line</li><li><strong>Ctrl+Enter</strong>: Press Ctrl+Enter to send; Enter for a new line</li></ul></li></ul><h3 id="reset-to-default" tabindex="-1">Reset to Default <a class="header-anchor" href="#reset-to-default" aria-label="Permalink to &quot;Reset to Default&quot;">​</a></h3><p>Click the &quot;Reset to Default&quot; button to restore all hotkeys to their original values.</p><h2 id="appearance" tabindex="-1">Appearance <a class="header-anchor" href="#appearance" aria-label="Permalink to &quot;Appearance&quot;">​</a></h2><p><img src="'+a+'" alt="Appearance settings"></p><p>Personalize NexusFlow&#39;s visual appearance.</p><h3 id="theme" tabindex="-1">Theme <a class="header-anchor" href="#theme" aria-label="Permalink to &quot;Theme&quot;">​</a></h3><p>Three theme modes are available:</p><ul><li><strong>Dark</strong> (default): VS Code Dark style — an eye-friendly dark theme</li><li><strong>Light</strong>: A bright, light theme</li><li><strong>Follow System</strong>: Automatically matches your Windows system theme</li></ul><h3 id="language" tabindex="-1">Language <a class="header-anchor" href="#language" aria-label="Permalink to &quot;Language&quot;">​</a></h3><p>Interface display language:</p><ul><li><strong>Follow System</strong>: Automatically matches your OS language</li><li><strong>简体中文</strong> (Simplified Chinese)</li><li><strong>繁體中文</strong> (Traditional Chinese)</li><li><strong>English</strong></li></ul><h3 id="font" tabindex="-1">Font <a class="header-anchor" href="#font" aria-label="Permalink to &quot;Font&quot;">​</a></h3><p>Click the font selector to open a full-screen font picker:</p><ul><li>Lists all fonts installed on your system</li><li>Search box for quick filtering</li><li>Each font previews in its own typeface</li><li>Click to select</li></ul><h3 id="font-size" tabindex="-1">Font Size <a class="header-anchor" href="#font-size" aria-label="Permalink to &quot;Font Size&quot;">​</a></h3><p>Choose the interface text size from 5 options:</p><ul><li>12px / 14px / <strong>16px</strong> (default) / 18px / 20px</li></ul><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Appearance changes are previewed in real time and saved automatically — no manual confirmation needed.</p></div><h2 id="about" tabindex="-1">About <a class="header-anchor" href="#about" aria-label="Permalink to &quot;About&quot;">​</a></h2><p><img src="'+i+'" alt="About page"></p><p>View application information and manage related settings.</p><h3 id="application-info" tabindex="-1">Application Info <a class="header-anchor" href="#application-info" aria-label="Permalink to &quot;Application Info&quot;">​</a></h3><ul><li><strong>Version</strong>: Current NexusFlow version</li><li><strong>Tauri Version</strong>: Underlying framework version</li></ul><h3 id="plugin-status" tabindex="-1">Plugin Status <a class="header-anchor" href="#plugin-status" aria-label="Permalink to &quot;Plugin Status&quot;">​</a></h3><p>Automatically detects Unreal Engine installations on your system and checks whether the NexusFlow plugin is correctly installed.</p><ul><li>Shows detected UE versions</li><li>Shows plugin installation status</li><li>Click &quot;Re-detect&quot; to refresh the status</li></ul><h3 id="anonymous-analytics" tabindex="-1">Anonymous Analytics <a class="header-anchor" href="#anonymous-analytics" aria-label="Permalink to &quot;Anonymous Analytics&quot;">​</a></h3><p>Optional anonymous usage data collection to help improve the product. You can enable or disable this at any time.</p><h3 id="links" tabindex="-1">Links <a class="header-anchor" href="#links" aria-label="Permalink to &quot;Links&quot;">​</a></h3><p>The following external links are provided (opened in your system browser):</p><ul><li>Official Website</li><li>Documentation</li><li>GitHub Repository</li><li>Feedback</li></ul><h3 id="license" tabindex="-1">License <a class="header-anchor" href="#license" aria-label="Permalink to &quot;License&quot;">​</a></h3><p>NexusFlow is open source under the MIT License. Click to expand and view the full license text.</p>',83)])])}const P=r(u,[["render",c]]);export{x as __pageData,P as default};
